Edit: NDArrayIter now supports h5py datasets, which is the recommended way for interacting with hdf5 data sets. See example a few comments below.

I basically put together a DataIter for HDF5 data in python. It is pretty much a clone of NDArrayDataIter  (without shuffeling as it is out of core).
See code and example below. The idea is to load data into memory batch by batch, hence it performs slower than NDArrayIter which has everything in memory.


(getlabel() update 15.08.2017)
```python
class HDF5ArrayIter(DataIter):

    def __init__(self, data, label, batch_size=1,
                 data_name="data", label_name="softmax_label",
                 last_batch_handle="pad"):
        super(HDF5ArrayIter, self).__init__(batch_size)

        self.data = data 
        self.label = label 
        self.batch_size = batch_size
        self.cursor = -batch_size
        self.num_data = data.shape[0]
        self.last_batch_handle = last_batch_handle
        self.data_name = data_name
        self.label_name = label_name


    @property
    def provide_data(self):
        return [DataDesc(self.data_name,
                         tuple([self.batch_size] + list(self.data.shape[1:])),
                         self.data.dtype)]

    @property
    def provide_label(self):
        return [DataDesc(self.label_name,
                         tuple([self.batch_size] + list(self.label.shape[1:])),
                         self.label.dtype)]

    def hard_reset(self):
        self.cursor = -self.batch_size

    def reset(self):
        if self.last_batch_handle == "roll_over" and self.cursor > self.num_data:
            self.cursor = -self.batch_size + (self.cursor % self.num_data) % self.batch_size
        else:
            self.cursor = -self.batch_size 


    def iter_next(self):
        self.cursor += self.batch_size
        return self.cursor < self.num_data


    def next(self):
        if self.iter_next():
            return DataBatch(data=self.getdata(),
                             label=self.getlabel(),
                             pad=self.getpad(),
                             index=None)
        else:
            raise StopIteration


    def getdata(self):
        assert(self.cursor < self.num_data), "DataIter needs reset."
        if self.cursor + self.batch_size <= self.num_data:
            return [array(self.data[self.cursor:self.cursor+self.batch_size])]
        else:
            pad = self.batch_size - self.num_data + self.cursor
            return [concatenate(array(self.data[self.cursor:]), array(self.data[:pad]))]


    def getlabel(self):
        assert(self.cursor < self.num_data), "DataIter needs reset."
        if self.cursor + self.batch_size <= self.num_data:
            return [array(self.label[self.cursor:self.cursor+self.batch_size])]
        else:
            pad = self.batch_size - self.num_data + self.cursor
            return [concatenate(array(self.label[self.cursor:]), array(self.label[:pad]))]


    def getpad(self):
        if self.last_batch_handle == "pad" and self.cursor + self.batch_size > self.num_data:
            return self.cursor + self.batch_size - self.num_data
        else:
            return 0
```
And finally to be used as follows:
```python
with h5py.File("myDataFile.hdf5", "r") as h5:
    X = h5["myData"]
    y = h5["myLabels"]
    train_iter = HDF5ArrayIter(X, y, BATCH_SIZE, last_batch_handle="pad")
```

I can submit a PR and add docs if people find it a good enough idea.
Comments?

Cheers
Andre

